func healthPill(h string) string {
	switch strings.ToLower(h) {
	case "ok":
		return "bg-sage/20 text-forest"
	case "attention":
		return "bg-ember/10 text-ember"
	case "urgent":
		return "bg-rust/10 text-rust"
	default:
		return "bg-muted/10 text-muted"
	}
}

func healthLabel(h string) string {
	switch strings.ToLower(h) {
	case "ok":
		return "OK"
	case "attention":
		return "CHÚ Ý"
	case "urgent":
		return "GẤP"
	default:
		return strings.ToUpper(h)
	}
}

func codeBg(status string) string {
	switch strings.ToLower(status) {
	case "active":
		return "bg-forest"
	case "paused":
		return "bg-muted"
	case "ended":
		return "bg-rust"
	default:
		return "bg-muted"
	}
}

